#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <cuda_runtime.h>

#include "common.h"

static inline float tvdiff_ms(const struct timeval *start, const struct timeval *end) {
    return (float)((end->tv_sec - start->tv_sec) * 1000.0 +
                   (end->tv_usec - start->tv_usec) / 1000.0);
}

static inline void cuda_check(cudaError_t err, const char *msg) {
    if (err != cudaSuccess) {
        printf("Cuda error: %s: %s.\n", msg, cudaGetErrorString(err));
        fflush(NULL);
        exit(EXIT_FAILURE);
    }
}

extern "C" int device_id_inuse;
extern "C" int platform_id_inuse;

__global__ void findK(long height,
                      knode *knodesD,
                      long knodes_elem,
                      record *recordsD,
                      long *currKnodeD,
                      long *offsetD,
                      int *keysD,
                      record *ansD)
{
    int thid = threadIdx.x;
    int bid = blockIdx.x;

    for (int i = 0; i < height; i++) {
        if ((knodesD[currKnodeD[bid]].keys[thid]) <= keysD[bid] &&
            (knodesD[currKnodeD[bid]].keys[thid + 1] > keysD[bid])) {
            if (knodesD[offsetD[bid]].indices[thid] < knodes_elem) {
                offsetD[bid] = knodesD[offsetD[bid]].indices[thid];
            }
        }

        __syncthreads();

        if (thid == 0) {
            currKnodeD[bid] = offsetD[bid];
        }

        __syncthreads();
    }

    if (knodesD[currKnodeD[bid]].keys[thid] == keysD[bid]) {
        ansD[bid].value = recordsD[knodesD[currKnodeD[bid]].indices[thid]].value;
    }
}

extern "C"
void kernel_gpu_cuda_wrapper(record *records,
                             long records_mem,
                             knode *knodes,
                             long knodes_elem,
                             long knodes_mem,
                             int order,
                             long maxheight,
                             int count,
                             long *currKnode,
                             long *offset,
                             int *keys,
                             record *ans)
{
#ifdef TIMING
    struct timeval tv_total_start, tv_init_end, tv_mem_alloc_end, tv_close_start, tv_close_end;
    struct timeval tv1, tv2;
    float init_time = 0.0f, mem_alloc_time = 0.0f, h2d_time = 0.0f;
    float kernel_time = 0.0f, d2h_time = 0.0f, close_time = 0.0f, total_time = 0.0f;
    gettimeofday(&tv_total_start, NULL);
#endif

    int device_count = 0;
    cuda_check(cudaGetDeviceCount(&device_count), "cudaGetDeviceCount");
    printf("Platform: NVIDIA CUDA\n");
    printf("Device num: %d\n", device_count);

    int dev = 0;
    if (device_id_inuse >= 0 && device_id_inuse < device_count) {
        dev = device_id_inuse;
    }
    cuda_check(cudaSetDevice(dev), "cudaSetDevice");

    cudaDeviceProp prop;
    cuda_check(cudaGetDeviceProperties(&prop, dev), "cudaGetDeviceProperties");
    printf("Creating GPU Context\n");
    printf("Device: %s\n", prop.name);

#ifdef TIMING
    gettimeofday(&tv_init_end, NULL);
    init_time = tvdiff_ms(&tv_total_start, &tv_init_end);
#endif

    record *recordsD = NULL;
    knode *knodesD = NULL;
    long *currKnodeD = NULL;
    long *offsetD = NULL;
    int *keysD = NULL;
    record *ansD = NULL;

    cuda_check(cudaMalloc((void **)&recordsD, (size_t)records_mem), "cudaMalloc recordsD");
    cuda_check(cudaMalloc((void **)&knodesD, (size_t)knodes_mem), "cudaMalloc knodesD");
    cuda_check(cudaMalloc((void **)&currKnodeD, (size_t)count * sizeof(long)), "cudaMalloc currKnodeD");
    cuda_check(cudaMalloc((void **)&offsetD, (size_t)count * sizeof(long)), "cudaMalloc offsetD");
    cuda_check(cudaMalloc((void **)&keysD, (size_t)count * sizeof(int)), "cudaMalloc keysD");
    cuda_check(cudaMalloc((void **)&ansD, (size_t)count * sizeof(record)), "cudaMalloc ansD");

#ifdef TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    mem_alloc_time = tvdiff_ms(&tv_init_end, &tv_mem_alloc_end);
    gettimeofday(&tv1, NULL);
#endif

    cuda_check(cudaMemcpy(recordsD, records, (size_t)records_mem, cudaMemcpyHostToDevice), "cudaMemcpy recordsD");
    cuda_check(cudaMemcpy(knodesD, knodes, (size_t)knodes_mem, cudaMemcpyHostToDevice), "cudaMemcpy knodesD");
    cuda_check(cudaMemcpy(currKnodeD, currKnode, (size_t)count * sizeof(long), cudaMemcpyHostToDevice), "cudaMemcpy currKnodeD");
    cuda_check(cudaMemcpy(offsetD, offset, (size_t)count * sizeof(long), cudaMemcpyHostToDevice), "cudaMemcpy offsetD");
    cuda_check(cudaMemcpy(keysD, keys, (size_t)count * sizeof(int), cudaMemcpyHostToDevice), "cudaMemcpy keysD");
    cuda_check(cudaMemcpy(ansD, ans, (size_t)count * sizeof(record), cudaMemcpyHostToDevice), "cudaMemcpy ansD");

#ifdef TIMING
    cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize h2d");
    gettimeofday(&tv2, NULL);
    h2d_time = tvdiff_ms(&tv1, &tv2);
#endif

    size_t local_work_size = order < 1024 ? (size_t)order : (size_t)1024;
    size_t global_work_size = (size_t)count * local_work_size;

    printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n",
           (int)(global_work_size / local_work_size), (int)local_work_size);

#ifdef TIMING
    gettimeofday(&tv1, NULL);
#endif

    findK<<<count, (unsigned int)local_work_size>>>(maxheight,
                                                    knodesD,
                                                    knodes_elem,
                                                    recordsD,
                                                    currKnodeD,
                                                    offsetD,
                                                    keysD,
                                                    ansD);
    cuda_check(cudaGetLastError(), "kernel launch findK");
    cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize findK");

#ifdef TIMING
    gettimeofday(&tv2, NULL);
    kernel_time = tvdiff_ms(&tv1, &tv2);
    gettimeofday(&tv1, NULL);
#endif

    cuda_check(cudaMemcpy(ans, ansD, (size_t)count * sizeof(record), cudaMemcpyDeviceToHost), "cudaMemcpy ans");

#ifdef TIMING
    cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize d2h");
    gettimeofday(&tv2, NULL);
    d2h_time = tvdiff_ms(&tv1, &tv2);
    gettimeofday(&tv_close_start, NULL);
#endif

    cudaFree(recordsD);
    cudaFree(knodesD);
    cudaFree(currKnodeD);
    cudaFree(offsetD);
    cudaFree(keysD);
    cudaFree(ansD);

#ifdef TIMING
    gettimeofday(&tv_close_end, NULL);
    close_time = tvdiff_ms(&tv_close_start, &tv_close_end);
    total_time = tvdiff_ms(&tv_total_start, &tv_close_end);

    printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
    printf("Init: %f\n", init_time);
    printf("MemAlloc: %f\n", mem_alloc_time);
    printf("HtoD: %f\n", h2d_time);
    printf("Exec: %f\n", kernel_time);
    printf("DtoH: %f\n", d2h_time);
    printf("Close: %f\n", close_time);
    printf("Total: %f\n", total_time);
#endif
}

