            i->next = itr;
            i->pred = itr->pred;
            itr->pred = i;
            i->pred->next = i;
        } else {
            l->tail->next = i;
            i->pred = l->tail;
            i->next = NULL;
            l->tail = i;
        }
    } else {
        l->head = l->tail = i;
        i->pred = i->next = NULL;
    }
    l->length++;
}

void
list_remove_item(list_t *l,
                 list_item_t *i)
{
    if (i == l->head) {
        l->head = l->head->next;
        if (l->head)
            l->head->pred = NULL;
        else
            l->tail = NULL;
    } else if (i == l->tail) {
        l->tail = l->tail->pred;
        l->tail->next = NULL;
    } else {
        i->pred->next = i->next;
        i->next->pred = i->pred;
    }
    l->length--;
    list_item_delete(i, l->datum_delete);
}

void
list_remove_head(list_t *l)
{
    list_remove_item(l, l->head);
}

void
list_remove_tail(list_t *l)
